[
    {
        "role": "paragraph",
        "segment": "Layered systems organize the system's software units into layers, each of which provides services to the layer above it and acts as a client to the layer below.",
        "citations": [
            {
                "type": "source_text",
                "content": "Layered systems organize the system's software units into layers, each of which provides services to the layer above it and acts as a client to the layer below.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "In a 'pure' layered system, a software unit in a given layer can access only the other units in the same layer and services offered by the interface to the layer immediately below it.",
        "citations": [
            {
                "type": "source_text",
                "content": "In a 'pure' layered system, a software unit in a given layer can access only the other units in the same layer and services offered by the interface to the layer immediately below it.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "To improve performance, this constraint may be relaxed in some cases, allowing a layer to access the services of layers below its lower neighbor; this is called layer bridging.",
        "citations": [
            {
                "type": "source_text",
                "content": "To improve performance, this constraint may be relaxed in some cases, allowing a layer to access the services of layers below its lower neighbor; this is called layer bridging.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "Under no circumstances does a layer access the services offered by a higher-level layer; the resulting architecture would no longer be called layered.",
        "citations": [
            {
                "type": "source_text",
                "content": "Under no circumstances does a layer access the services offered by a higher-level layer; the resulting architecture would no longer be called layered.",
                "img_id": null
            }
        ],
        "type": null
    }
]

[
    {
        "role": "paragraph",
        "segment": "Layer bridging is a relaxation of the strict layered system constraint, allowing a layer to access the services of layers below its immediate lower neighbor.",
        "citations": [
            {
                "type": "source_text",
                "content": "To improve performance, this constraint may be relaxed in some cases, allowing a layer to access the services of layers below its lower neighbor; this is called layer bridging .",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "However, extensive layer bridging reduces the portability and maintainability benefits of the layering style.",
        "citations": [
            {
                "type": "source_text",
                "content": "However, if a design includes a lot of layer bridging, then it loses some of the portability and maintainability that the layering style offers.",
                "img_id": null
            }
        ],
        "type": null
    }
]

